class KnowledgeBase:
    def __init__(self):
        self.indexes: dict[str, VectorStoreIndex] = {}
        self.router: RouterQueryEngine | None = None
        self.parser = SentenceSplitter(chunk_size=512, chunk_overlap=50)

    def add_document(self, doc: Document, topic: str) -> None:
        nodes = self.parser.get_nodes_from_documents([doc])
        if topic not in self.indexes:
            self.indexes[topic] = VectorStoreIndex(nodes)
        else:
            self.indexes[topic].insert_nodes(nodes)
        self._rebuild_router()

    def _rebuild_router(self) -> None:
        tools = [
            QueryEngineTool.from_defaults(
                query_engine=idx.as_query_engine(similarity_top_k=3),
                name=topic.replace('-', '_'),
                description=f'Contains documents about {topic}'
            )
            for topic, idx in self.indexes.items()
        ]
        self.router = RouterQueryEngine(
            selector=LLMSingleSelector.from_defaults(),
            query_engine_tools=tools
        )

    def query(self, question: str) -> str:
        if not self.router:
            return 'No documents indexed yet.'
        return str(self.router.query(question))
